-- Initial synchronized persistence schema. All instants use TIMESTAMPTZ(3).
CREATE TYPE "OwnerStatus" AS ENUM ('ACTIVE', 'ARCHIVED');
CREATE TYPE "DevicePlatform" AS ENUM ('WINDOWS', 'ANDROID');
CREATE TYPE "DeviceStatus" AS ENUM ('ACTIVE', 'REVOKED', 'RETIRED');
CREATE TYPE "PairingStatus" AS ENUM ('PENDING', 'APPROVED', 'CANCELLED', 'EXPIRED', 'CONSUMED');
CREATE TYPE "SessionStatus" AS ENUM ('ACTIVE', 'PAUSED', 'STOPPED', 'COMPLETED');
CREATE TYPE "ReminderState" AS ENUM ('SCHEDULED', 'DUE', 'PRESENTED', 'SNOOZED', 'COMPLETED', 'SKIPPED', 'EMERGENCY_DISMISSED', 'MISSED', 'SUPERSEDED');
CREATE TYPE "SyncOperationStatus" AS ENUM ('ACCEPTED', 'REJECTED', 'CONFLICT');
CREATE TYPE "ConflictStatus" AS ENUM ('OPEN', 'RESOLVED', 'DISMISSED');
CREATE TYPE "BackupKind" AS ENUM ('BACKUP', 'EXPORT');

CREATE TABLE "owners" ("id" VARCHAR(26) PRIMARY KEY, "status" "OwnerStatus" NOT NULL DEFAULT 'ACTIVE', "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMPTZ(3) NOT NULL);
CREATE TABLE "devices" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "publicKey" TEXT NOT NULL UNIQUE, "fingerprint" VARCHAR(128) NOT NULL UNIQUE, "platform" "DevicePlatform" NOT NULL, "displayName" VARCHAR(120), "capabilities" JSONB, "isOwnerDevice" BOOLEAN NOT NULL DEFAULT false, "status" "DeviceStatus" NOT NULL DEFAULT 'ACTIVE', "lastSeenAt" TIMESTAMPTZ(3), "revokedAt" TIMESTAMPTZ(3), "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMPTZ(3) NOT NULL);
CREATE TABLE "device_pairings" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "candidatePublicKey" TEXT NOT NULL, "candidateFingerprint" VARCHAR(128) NOT NULL, "candidatePlatform" "DevicePlatform" NOT NULL, "status" "PairingStatus" NOT NULL DEFAULT 'PENDING', "approvedByDeviceId" VARCHAR(26) REFERENCES "devices"("id") ON DELETE SET NULL, "expiresAt" TIMESTAMPTZ(3) NOT NULL, "approvedAt" TIMESTAMPTZ(3), "consumedAt" TIMESTAMPTZ(3), "cancelledAt" TIMESTAMPTZ(3), "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("ownerId", "candidateFingerprint"));
CREATE TABLE "focus_modes" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "name" VARCHAR(120) NOT NULL, "intervalMinutes" INTEGER NOT NULL, "policy" JSONB NOT NULL, "version" VARCHAR(26) NOT NULL, "deletedAt" TIMESTAMPTZ(3), "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMPTZ(3) NOT NULL, UNIQUE("ownerId", "name"));
CREATE TABLE "focus_sessions" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "focusModeId" VARCHAR(26) NOT NULL REFERENCES "focus_modes"("id") ON DELETE RESTRICT, "name" VARCHAR(160), "status" "SessionStatus" NOT NULL DEFAULT 'ACTIVE', "schedulePolicy" JSONB NOT NULL, "timezoneId" VARCHAR(64) NOT NULL, "startedAt" TIMESTAMPTZ(3) NOT NULL, "endedAt" TIMESTAMPTZ(3), "version" VARCHAR(26) NOT NULL, "deletedAt" TIMESTAMPTZ(3), "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMPTZ(3) NOT NULL);
CREATE TABLE "reminder_occurrences" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "focusSessionId" VARCHAR(26) NOT NULL REFERENCES "focus_sessions"("id") ON DELETE RESTRICT, "state" "ReminderState" NOT NULL DEFAULT 'SCHEDULED', "scheduledAt" TIMESTAMPTZ(3) NOT NULL, "originalScheduledAt" TIMESTAMPTZ(3) NOT NULL, "presentedAt" TIMESTAMPTZ(3), "resolvedAt" TIMESTAMPTZ(3), "timezoneId" VARCHAR(64) NOT NULL, "policySnapshot" JSONB NOT NULL, "version" VARCHAR(26) NOT NULL, "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMPTZ(3) NOT NULL);
CREATE TABLE "reminder_transitions" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL, "reminderOccurrenceId" VARCHAR(26) NOT NULL REFERENCES "reminder_occurrences"("id") ON DELETE RESTRICT, "actingDeviceId" VARCHAR(26) REFERENCES "devices"("id") ON DELETE SET NULL, "fromState" "ReminderState" NOT NULL, "toState" "ReminderState" NOT NULL, "reason" VARCHAR(500), "originalScheduledAt" TIMESTAMPTZ(3) NOT NULL, "occurredAt" TIMESTAMPTZ(3) NOT NULL, "operationId" VARCHAR(26) NOT NULL UNIQUE, "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "categories" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "name" VARCHAR(80) NOT NULL, "color" VARCHAR(32), "version" VARCHAR(26) NOT NULL, "deletedAt" TIMESTAMPTZ(3), "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMPTZ(3) NOT NULL, UNIQUE("ownerId", "name"));
CREATE TABLE "check_ins" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "reminderOccurrenceId" VARCHAR(26) UNIQUE REFERENCES "reminder_occurrences"("id") ON DELETE SET NULL, "focusSessionId" VARCHAR(26) REFERENCES "focus_sessions"("id") ON DELETE SET NULL, "categoryId" VARCHAR(26) REFERENCES "categories"("id") ON DELETE SET NULL, "currentRevisionId" VARCHAR(26), "submittedAt" TIMESTAMPTZ(3) NOT NULL, "timezoneId" VARCHAR(64) NOT NULL, "version" VARCHAR(26) NOT NULL, "deletedAt" TIMESTAMPTZ(3), "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMPTZ(3) NOT NULL);
CREATE TABLE "check_in_revisions" ("id" VARCHAR(26) PRIMARY KEY, "checkInId" VARCHAR(26) NOT NULL REFERENCES "check_ins"("id") ON DELETE RESTRICT, "parentRevisionId" VARCHAR(26), "body" TEXT NOT NULL, "authorDeviceId" VARCHAR(26), "operationId" VARCHAR(26) NOT NULL UNIQUE, "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "deletedAt" TIMESTAMPTZ(3));
CREATE TABLE "tags" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "name" VARCHAR(80) NOT NULL, "color" VARCHAR(32), "version" VARCHAR(26) NOT NULL, "deletedAt" TIMESTAMPTZ(3), "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMPTZ(3) NOT NULL, UNIQUE("ownerId", "name"));
CREATE TABLE "check_in_tags" ("checkInId" VARCHAR(26) NOT NULL REFERENCES "check_ins"("id") ON DELETE RESTRICT, "tagId" VARCHAR(26) NOT NULL REFERENCES "tags"("id") ON DELETE RESTRICT, PRIMARY KEY("checkInId", "tagId"));
CREATE TABLE "sync_operations" ("operationId" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "deviceId" VARCHAR(26) NOT NULL REFERENCES "devices"("id") ON DELETE RESTRICT, "deviceSequence" BIGINT NOT NULL, "entityType" VARCHAR(80) NOT NULL, "entityId" VARCHAR(26) NOT NULL, "kind" VARCHAR(120) NOT NULL, "baseVersion" VARCHAR(26), "payload" JSONB NOT NULL, "occurredAt" TIMESTAMPTZ(3) NOT NULL, "receivedAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "status" "SyncOperationStatus" NOT NULL DEFAULT 'ACCEPTED', "result" JSONB, "sequence" BIGINT, UNIQUE("ownerId", "deviceId", "deviceSequence"), UNIQUE("ownerId", "sequence"));
CREATE TABLE "sync_cursors" ("ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "deviceId" VARCHAR(26) NOT NULL UNIQUE REFERENCES "devices"("id") ON DELETE RESTRICT, "lastAppliedSequence" BIGINT NOT NULL DEFAULT 0, "updatedAt" TIMESTAMPTZ(3) NOT NULL, PRIMARY KEY("ownerId", "deviceId"));
CREATE TABLE "conflicts" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "entityType" VARCHAR(80) NOT NULL, "entityId" VARCHAR(26) NOT NULL, "localOperationId" VARCHAR(26), "remoteOperationId" VARCHAR(26), "localPayload" JSONB, "remotePayload" JSONB, "status" "ConflictStatus" NOT NULL DEFAULT 'OPEN', "resolvedAt" TIMESTAMPTZ(3), "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "backup_manifests" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "kind" "BackupKind" NOT NULL DEFAULT 'BACKUP', "formatVersion" INTEGER NOT NULL, "schemaVersion" INTEGER NOT NULL, "storageLocation" TEXT NOT NULL, "checksum" VARCHAR(128) NOT NULL, "encryption" JSONB NOT NULL, "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "expiresAt" TIMESTAMPTZ(3));
CREATE TABLE "settings" ("ownerId" VARCHAR(26) PRIMARY KEY REFERENCES "owners"("id") ON DELETE RESTRICT, "values" JSONB NOT NULL, "version" VARCHAR(26) NOT NULL, "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMPTZ(3) NOT NULL);
CREATE TABLE "tombstones" ("id" VARCHAR(26) PRIMARY KEY, "ownerId" VARCHAR(26) NOT NULL REFERENCES "owners"("id") ON DELETE RESTRICT, "entityType" VARCHAR(80) NOT NULL, "entityId" VARCHAR(26) NOT NULL, "version" VARCHAR(26) NOT NULL, "deletedAt" TIMESTAMPTZ(3) NOT NULL, "retentionUntil" TIMESTAMPTZ(3) NOT NULL, "createdAt" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("ownerId", "entityType", "entityId"));

CREATE INDEX "devices_ownerId_status_idx" ON "devices"("ownerId", "status");
CREATE INDEX "devices_ownerId_lastSeenAt_idx" ON "devices"("ownerId", "lastSeenAt");
CREATE INDEX "device_pairings_ownerId_status_expiresAt_idx" ON "device_pairings"("ownerId", "status", "expiresAt");
CREATE INDEX "focus_modes_ownerId_deletedAt_idx" ON "focus_modes"("ownerId", "deletedAt");
CREATE INDEX "focus_sessions_ownerId_status_startedAt_idx" ON "focus_sessions"("ownerId", "status", "startedAt");
CREATE INDEX "focus_sessions_ownerId_deletedAt_idx" ON "focus_sessions"("ownerId", "deletedAt");
CREATE INDEX "reminder_occurrences_ownerId_state_scheduledAt_idx" ON "reminder_occurrences"("ownerId", "state", "scheduledAt");
CREATE INDEX "reminder_occurrences_focusSessionId_scheduledAt_idx" ON "reminder_occurrences"("focusSessionId", "scheduledAt");
CREATE INDEX "reminder_transitions_ownerId_occurredAt_idx" ON "reminder_transitions"("ownerId", "occurredAt");
CREATE INDEX "reminder_transitions_reminderOccurrenceId_occurredAt_idx" ON "reminder_transitions"("reminderOccurrenceId", "occurredAt");
CREATE INDEX "check_ins_ownerId_submittedAt_idx" ON "check_ins"("ownerId", "submittedAt");
CREATE INDEX "check_ins_ownerId_deletedAt_idx" ON "check_ins"("ownerId", "deletedAt");
CREATE INDEX "check_ins_focusSessionId_submittedAt_idx" ON "check_ins"("focusSessionId", "submittedAt");
CREATE INDEX "check_in_revisions_checkInId_createdAt_idx" ON "check_in_revisions"("checkInId", "createdAt");
CREATE INDEX "tags_ownerId_deletedAt_idx" ON "tags"("ownerId", "deletedAt");
CREATE INDEX "categories_ownerId_deletedAt_idx" ON "categories"("ownerId", "deletedAt");
CREATE INDEX "check_in_tags_tagId_idx" ON "check_in_tags"("tagId");
CREATE INDEX "sync_operations_ownerId_receivedAt_idx" ON "sync_operations"("ownerId", "receivedAt");
CREATE INDEX "sync_operations_ownerId_entityType_entityId_idx" ON "sync_operations"("ownerId", "entityType", "entityId");
CREATE INDEX "conflicts_ownerId_status_createdAt_idx" ON "conflicts"("ownerId", "status", "createdAt");
CREATE INDEX "conflicts_ownerId_entityType_entityId_idx" ON "conflicts"("ownerId", "entityType", "entityId");
CREATE INDEX "backup_manifests_ownerId_createdAt_idx" ON "backup_manifests"("ownerId", "createdAt");
CREATE INDEX "tombstones_ownerId_retentionUntil_idx" ON "tombstones"("ownerId", "retentionUntil");
